function generateSignatureForChunks(chunkedData) {
  // 检查chunkedData是否有效
  if (!Array.isArray(chunkedData)) {
    throw new Error('Invalid input: chunkedData is not an array');
  }

  return chunkedData.map((chunk, index) => {
    // 检查每个chunk的结构是否符合预期
    if (!chunk || !chunk.json || !Array.isArray(chunk.json.details)) {
      console.error(`Invalid chunk at index ${index}:`, chunk);
      throw new Error(`Invalid chunk format at index ${index}`);
    }

    // 对每个块内的数据进行签名生成
    const outputData = {
      body: chunk.json.details.map(item => ({
        seqId: item.seqId,
        mfrInfo: item.mfrInfo,
        brand: item.brand,
        barcode: item.barcode,
        retailPrice: item.retailPrice,
        region: item.region,
        isAIProduct: item.isAIProduct,
        snCode: item.snCode,
        saleStatus: item.saleStatus,
        mfgTime: item.mfgTime,
        cateCode: item.cateCode,
        specModel: item.specModel
      })),
      keyid: "REDACTED",
      key: "REDACTED",
      timestamp: Date.now() // 获取当前时间戳
    };

    return { json: outputData };
  });
}

