  const response = httpResponses[index];
  const data = response.data;
  const excludeSeqIds = new Set();
  let includeAll = false;
  let excludeAll = false;

  if (data) {
    if (data.checkCode === "T0000") {
      // 如果 code 为 T0000，直接包含所有数据
      includeAll = true;
    } else if (data.checkCode === "T9999") {
      // 如果 code 为 T9999，不返回任何数据
      excludeAll = true;
    } else if (data.checkCode === "T0002" || data.checkCode === "T0080") {
      // T0002 和 T0080 逻辑相同，记录需要剔除的 seqId
      if (data.returnInfo) {
        data.returnInfo.forEach(info => {
          excludeSeqIds.add(info.seqId);
        });
      }
    }
  }

  // 过滤掉需要剔除的数据
  item.body.forEach(data => {
    if (includeAll) {
      snCodes.push({ snCode: data.snCode });
    } else if (!excludeAll && !excludeSeqIds.has(data.seqId)) {
      snCodes.push({ snCode: data.snCode });
    }
  });
});

// 返回 snCode 数组
